export function getCareerBySlug(slug: string): Career | undefined {
    return careers.find(c => c.slug === slug);
}

export function getCareersByCategory(category: string): Career[] {
    return careers.filter(c => c.subcategory === category || c.category === category);
}

export function getTrendingCareers(): Career[] {
    return careers.filter(c => c.trending).sort((a, b) => b.futureGrowth - a.futureGrowth);
}

export function searchCareers(query: string): Career[] {
    const q = query.toLowerCase();
    return careers.filter(c =>
        c.name.toLowerCase().includes(q) ||
        c.tags.some(t => t.includes(q)) ||
        c.skills.some(s => s.toLowerCase().includes(q)) ||
        c.category.toLowerCase().includes(q) ||
        c.stream.toLowerCase().includes(q)
    );
}

